#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int countUniqueEmailGroups(vector<string>& emails) {
        unordered_set<string> st;
        for (string email : emails) {
            size_t atPos = email.find('@');
            string local = email.substr(0, atPos);
            string domain = email.substr(atPos + 1);
            transform(domain.begin(), domain.end(), domain.begin(), ::tolower);
            transform(local.begin(), local.end(), local.begin(), ::tolower);
            size_t plusPos = local.find('+');
            if (plusPos != string::npos) {
                local = local.substr(0, plusPos);
            }
            local.erase(remove(local.begin(), local.end(), '.'), local.end());
            st.insert(local + "@" + domain);
        }
        return st.size();
    }
};

class solution:
    def countUniqueEmailGroups(self, emails):
        st = set()
        for email in emails:
            local, domain = email.split('@', 1)
            domain = domain.lower()
            local = local.lower()
            plus = local.find('+')
            if plus != -1:
                local = local[:plus]
            local = local.replace('.', '')
            st.add(local + '@' + domain)
        return len(st)

import java.util.*;

public class Solution {
    public int countUniqueEmailGroups(String[] emails) {
        Set<String> st = new HashSet<>();
        for (String email : emails) {
            String[] parts = email.split("@", 2);
            String local = parts[0].toLowerCase();
            String domain = parts[1].toLowerCase();
            int plus = local.indexOf('+');
            if (plus != -1) {
                local = local.substring(0, plus);
            }
            local = local.replace(".", "");
            st.add(local + "@" + domain);
        }
        return st.size();
    }
}

class Solution {
    countUniqueEmailGroups(emails) {
        const st = new Set();
        for (let email of emails) {
            let [local, domain] = email.split('@');
            domain = domain.toLowerCase();
            local = local.toLowerCase();
            const plus = local.indexOf('+');
            if (plus !== -1) {
                local = local.substring(0, plus);
            }
            local = local.replace(/\./g, '');
            st.add(local + '@' + domain);
        }
        return st.size;
    }
}

