import java.util.*;

public class Solution {
    public int calculateTypingDistance(String text) {
        Map<Character, int[]> pos = new HashMap<>();
        String row0 = "qwertyuiop";
        String row1 = "asdfghjkl";
        String row2 = "zxcvbnm";
        for (int c = 0; c < row0.length(); c++) {
            pos.put(row0.charAt(c), new int[]{0, c});
        }
        for (int c = 0; c < row1.length(); c++) {
            pos.put(row1.charAt(c), new int[]{1, c});
        }
        for (int c = 0; c < row2.length(); c++) {
            pos.put(row2.charAt(c), new int[]{2, c});
        }
        int ans = 0;
        char cur = 'a';
        for (char ch : text.toCharArray()) {
            int[] currentPos = pos.get(cur);
            int[] nextPos = pos.get(ch);
            ans += Math.abs(currentPos[0] - nextPos[0]) + Math.abs(currentPos[1] - nextPos[1]);
            cur = ch;
        }
        return ans;
    }
}

